1	/**
2	 * Claude Code Session Provider
3	 *
4	 * Apparatus plugin that implements AnimatorSessionProvider for the
5	 * Claude Code CLI. The Animator discovers this via guild config:
6	 *
7	 *   guild.json["animator"]["sessionProvider"] = "claude-code"
8	 *
9	 * Launches sessions via the `claude` CLI in autonomous mode (--print)
10	 * with --output-format stream-json for structured telemetry.
11	 *
12	 * Key design choice: uses async spawn() instead of spawnSync().
13	 * This is required for stream-json transcript parsing, timeout enforcement,
14	 * and future concurrent session support.
15	 */
16	
17	import { spawn } from 'node:child_process';
18	import fs from 'node:fs';
19	import os from 'node:os';
20	import path from 'node:path';
21	
22	import type { Plugin } from '@shardworks/nexus-core';
23	import { guild } from '@shardworks/nexus-core';
24	import type {
25	  AnimatorSessionProvider,
26	  SessionProviderConfig,
27	  SessionProviderResult,
28	  SessionChunk,
29	} from '@shardworks/animator-apparatus';
30	
31	import { startMcpHttpServer } from './mcp-server.ts';
32	import type { McpHttpHandle } from './mcp-server.ts';
33	import { launchDetached, type DetachedLaunchOptions } from './detached.ts';
34	
35	// ‚îÄ‚îÄ Session File Preparation ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
36	
37	/** Prepared session files in a temp directory. */
38	interface PreparedSession {
39	  tmpDir: string;
40	  args: string[];
41	  /** If an MCP server was started, this handle closes it. */
42	  mcpHandle?: McpHttpHandle;
43	}
44	
45	/**
46	 * Prepare session files and build base CLI args.
47	 *
48	 * Writes system prompt to a temp directory. Builds the base args array
49	 * including --resume support. When tools are provided, starts an
50	 * in-process MCP HTTP server and writes --mcp-config.
51	 *
52	 * Caller is responsible for cleaning up tmpDir and calling mcpHandle.close().
53	 */
54	async function prepareSession(config: SessionProviderConfig): Promise<PreparedSession> {
55	  const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), 'nsg-session-'));
56	
57	  const args: string[] = [
58	    '--setting-sources', 'user',
59	    '--dangerously-skip-permissions',
60	    '--model', config.model,
61	  ];
62	
63	  if (config.systemPrompt) {
64	    const systemPromptPath = path.join(tmpDir, 'system-prompt.md');
65	    fs.writeFileSync(systemPromptPath, config.systemPrompt);
66	    args.push('--system-prompt-file', systemPromptPath);
67	  }
68	
69	  // Resume an existing conversation
70	  if (config.conversationId) {
71	    args.push('--resume', config.conversationId);
72	  }
73	
74	  // Tool-equipped session: start MCP HTTP server, write --mcp-config
75	  let mcpHandle: McpHttpHandle | undefined;
76	
77	  if (config.tools && config.tools.length > 0) {
78	    const tools = config.tools.map((rt) => rt.definition);
79	    mcpHandle = await startMcpHttpServer(tools);
80	
81	    const mcpConfig = {
82	      mcpServers: {
83	        'nexus-guild': {
84	          type: 'sse',
85	          url: mcpHandle.url,
86	        },
87	      },
88	    };
89	
90	    const mcpConfigPath = path.join(tmpDir, 'mcp-config.json');
91	    fs.writeFileSync(mcpConfigPath, JSON.stringify(mcpConfig));
92	    args.push('--mcp-config', mcpConfigPath, '--strict-mcp-config');
93	  }
94	
95	  return { tmpDir, args, mcpHandle };
96	}
97	
98	// ‚îÄ‚îÄ Output extraction ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
99	
100	/**
101	 * Extract the final assistant text from a transcript.
102	 *
103	 * Walks the transcript backwards to find the last `assistant` message
104	 * and concatenates its text content blocks.
105	 *
106	 * @internal Exported for testing only.
107	 */
108	export function extractFinalAssistantText(transcript: Record<string, unknown>[]): string | undefined {
109	  for (let i = transcript.length - 1; i >= 0; i--) {
110	    const msg = transcript[i]!;
111	    if (msg.type !== 'assistant') continue;
112	
113	    const message = msg.message as Record<string, unknown> | undefined;
114	    const content = message?.content as Array<Record<string, unknown>> | undefined;
115	    if (!content) continue;
116	
117	    const text = content
118	      .filter((block) => block.type === 'text' && typeof block.text === 'string')
119	      .map((block) => block.text as string)
120	      .join('');
121	
122	    return text || undefined;
123	  }
124	  return undefined;
125	}
126	
127	// ‚îÄ‚îÄ Result builder ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
128	
129	function buildResult(raw: StreamJsonResult): SessionProviderResult {
130	  const status = raw.exitCode === 0 ? 'completed' as const : 'failed' as const;
131	  return {
132	    status,
133	    exitCode: raw.exitCode,
134	    error: status === 'failed' ? `claude exited with code ${raw.exitCode}` : undefined,
135	    costUsd: raw.costUsd,
136	    tokenUsage: raw.tokenUsage,
137	    providerSessionId: raw.providerSessionId,
138	    transcript: raw.transcript,
139	    output: extractFinalAssistantText(raw.transcript),
140	  };
141	}
142	
143	// ‚îÄ‚îÄ Provider implementation ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
144	
145	const provider: AnimatorSessionProvider = {
146	  name: 'claude-code',
147	
148	  async cancel(cancelMetadata: Record<string, unknown>): Promise<void> {
149	    const pid = cancelMetadata.pid as number | undefined;
150	    if (pid === undefined) return;
151	    try {
152	      process.kill(pid, 'SIGTERM');
153	    } catch (err: unknown) {
154	      if ((err as NodeJS.ErrnoException).code === 'ESRCH') {
155	        // Process already dead ‚Äî expected for race conditions. Silent no-op.
156	        return;
157	      }
158	      throw err;
159	    }
160	  },
161	
162	  launch(config: SessionProviderConfig): {
163	    chunks: AsyncIterable<SessionChunk>;
164	    result: Promise<SessionProviderResult>;
165	    processInfo?: Promise<Record<string, unknown>>;
166	  } {
167	    // Detached mode is the default: spawn a babysitter process that survives
168	    // guild restarts, hosts the MCP server, spawns claude, streams transcripts
169	    // to SQLite, and reports lifecycle events via HTTP.
170	    //
171	    // Escape hatch: guild.json["animator"]["detached"] = false opts out and
172	    // runs claude in-process (attached mode) for debugging.
173	    let detached = true;
174	    try {
175	      const animatorConfig = guild().guildConfig().animator as
176	        | { detached?: boolean }
177	        | undefined;
178	      if (animatorConfig?.detached === false) detached = false;
179	    } catch {
180	      // No guild bound (e.g. unit tests) ‚Äî fall back to detached default.
181	    }
182	    return detached ? launchDetached(config) : launchAttached(config);
183	  },
184	};
185	
186	// ‚îÄ‚îÄ Attached launch (preserved for debugging / non-detached mode) ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
187	
188	/**
189	 * Launch a session in attached mode ‚Äî claude as a direct child process.
190	 *
191	 * Preserved for debugging and potential future "attached mode" escape hatch.
192	 * Not currently wired into the provider, but all supporting code is kept.
193	 *
194	 * @internal
195	 */
196	export function launchAttached(config: SessionProviderConfig): {
197	  chunks: AsyncIterable<SessionChunk>;
198	  result: Promise<SessionProviderResult>;
199	  processInfo?: Promise<Record<string, unknown>>;
200	} {
201	    // prepareSession is async (MCP server start), so we wrap the launch
202	    // in a promise. The chunks iterable bridges the async gap ‚Äî it waits
203	    // for prep to complete before yielding.
204	
205	    let chunkResolve: (() => void) | null = null;
206	    let innerChunks: AsyncIterable<SessionChunk> | null = null;
207	    let innerIterator: AsyncIterator<SessionChunk> | null = null;
208	    let prepDone = false;
209	    let prepError: Error | null = null;
210	    let done = false;
211	
212	    // processInfo promise ‚Äî resolved with { pid } once the process spawns.
213	    let resolveProcessInfo: ((info: Record<string, unknown>) => void) | null = null;
214	    let rejectProcessInfo: ((err: Error) => void) | null = null;
215	    const processInfo = new Promise<Record<string, unknown>>((resolve, reject) => {
216	      resolveProcessInfo = resolve;
217	      rejectProcessInfo = reject;
218	    });
219	
220	    const result = prepareSession(config).then(async ({ tmpDir, args, mcpHandle }) => {
221	      // Autonomous mode: prompt piped via stdin (--print - reads from stdin).
222	      // This avoids Commander parsing issues when the prompt starts with '-'
223	      // (e.g. YAML frontmatter '---') and also avoids OS arg length limits.
224	      const prompt = config.initialPrompt ?? '';
225	      args.push(
226	        '--print', '-',
227	        '--output-format', 'stream-json',
228	        '--verbose',
229	      );
230	
231	      const cleanup = async () => {
232	        await mcpHandle?.close().catch(() => {});
233	        fs.rmSync(tmpDir, { recursive: true, force: true });
234	      };
235	
236	      try {
237	        if (config.streaming) {
238	          const spawned = spawnClaudeStreamingJson(args, config.cwd, config.environment, prompt);
239	          resolveProcessInfo!({ pid: spawned.pid });
240	          innerChunks = spawned.chunks;
241	          prepDone = true;
242	          if (chunkResolve) { chunkResolve(); chunkResolve = null; }
243	
244	          const raw = await spawned.result;
245	          await cleanup();
246	          return buildResult(raw);
247	        }
248	
249	        // Non-streaming
250	        const { result: spawnResult, pid } = spawnClaudeStreamJson(args, config.cwd, config.environment, prompt);
251	        resolveProcessInfo!({ pid });
252	        prepDone = true;
253	        done = true;
254	        if (chunkResolve) { chunkResolve(); chunkResolve = null; }
255	
256	        const raw = await spawnResult;
257	        await cleanup();
258	        return buildResult(raw);
259	      } catch (err) {
260	        await cleanup();
261	        throw err;
262	      }
263	    }).catch((err) => {
264	      // If prep itself failed, unblock the chunk iterator and processInfo
265	      prepError = err instanceof Error ? err : new Error(String(err));
266	      prepDone = true;
267	      done = true;
268	      if (chunkResolve) { chunkResolve(); chunkResolve = null; }
269	      rejectProcessInfo!(prepError);
270	      throw err;
271	    });
272	
273	    // Chunks iterable that bridges the async prep gap. In non-streaming
274	    // mode or on error, it completes immediately with no items.
275	    const chunks: AsyncIterable<SessionChunk> = {
276	      [Symbol.asyncIterator]() {
277	        return {
278	          async next(): Promise<IteratorResult<SessionChunk>> {
279	            // Wait for prep to complete
280	            while (!prepDone) {
281	              await new Promise<void>((resolve) => { chunkResolve = resolve; });
282	            }
283	
284	            if (prepError || done) {
285	              return { value: undefined as unknown as SessionChunk, done: true };
286	            }
287	
288	            // Delegate to inner streaming iterator
289	            if (innerChunks && !innerIterator) {
290	              innerIterator = innerChunks[Symbol.asyncIterator]();
291	            }
292	
293	            if (innerIterator) {
294	              return innerIterator.next();
295	            }
296	
297	            return { value: undefined as unknown as SessionChunk, done: true };
298	          },
299	        };
300	      },
301	    };
302	
303	    return { chunks, result, processInfo };
304	}
305	
306	// ‚îÄ‚îÄ Apparatus export ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
307	
308	/**
309	 * Create the Claude Code session provider apparatus.
310	 *
311	 * The apparatus has no startup logic ‚Äî it just provides the
312	 * AnimatorSessionProvider implementation. The Animator looks it up
313	 * via guild().apparatus('claude-code').
314	 */
315	export function createClaudeCodeProvider(): Plugin {
316	  return {
317	    apparatus: {
318	      requires: [],
319	      provides: provider,
320	
321	      start() {
322	        // No startup work ‚Äî the provider is stateless.
323	      },
324	    },
325	  };
326	}
327	
328	export default createClaudeCodeProvider();
329	
330	// ‚îÄ‚îÄ MCP server re-exports ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
331	// The MCP server module is used by the session provider to attach tools
332	// to sessions via --mcp-config, and can be imported directly for
333	// testing or custom integrations.
334	
335	export { createMcpServer, startMcpHttpServer } from './mcp-server.ts';
336	export type { McpHttpHandle } from './mcp-server.ts';
337	
338	// ‚îÄ‚îÄ Spawn helpers ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
339	
340	/** Parsed result from stream-json output. @internal */
341	export interface StreamJsonResult {
342	  exitCode: number;
343	  transcript: Record<string, unknown>[];
344	  costUsd?: number;
345	  tokenUsage?: {
346	    inputTokens: number;
347	    outputTokens: number;
348	    cacheReadTokens?: number;
349	    cacheWriteTokens?: number;
350	  };
351	  providerSessionId?: string;
352	}
353	
354	/**
355	 * Parse a single NDJSON message from stream-json output.
356	 *
357	 * Returns parsed chunks for streaming and accumulates data into the
358	 * provided accumulators (transcript, metrics).
359	 *
360	 * @internal Exported for testing only.
361	 */
362	export function parseStreamJsonMessage(
363	  msg: Record<string, unknown>,
364	  acc: {
365	    transcript: Record<string, unknown>[];
366	    costUsd?: number;
367	    tokenUsage?: StreamJsonResult['tokenUsage'];
368	    providerSessionId?: string;
369	  },
370	): SessionChunk[] {
371	  const chunks: SessionChunk[] = [];
372	
373	  if (msg.type === 'assistant') {
374	    acc.transcript.push(msg);
375	
376	    const message = msg.message as Record<string, unknown> | undefined;
377	    if (message) {
378	      const content = message.content as Array<Record<string, unknown>> | undefined;
379	      if (content) {
380	        for (const block of content) {
381	          if (block.type === 'text' && typeof block.text === 'string') {
382	            process.stderr.write(block.text);
383	            chunks.push({ type: 'text', text: block.text });
384	          } else if (block.type === 'tool_use' && typeof block.name === 'string') {
385	            chunks.push({ type: 'tool_use', tool: block.name });
386	          }
387	        }
388	      }
389	    }
390	  } else if (msg.type === 'user') {
391	    acc.transcript.push(msg);
392	
393	    const content = (msg as Record<string, unknown>).content as Array<Record<string, unknown>> | undefined;
394	    if (content) {
395	      for (const block of content) {
396	        if (block.type === 'tool_result' && typeof block.tool_use_id === 'string') {
397	          chunks.push({ type: 'tool_result', tool: String(block.tool_use_id) });
398	        }
399	      }
400	    }
401	  } else if (msg.type === 'result') {
402	    acc.costUsd = typeof msg.total_cost_usd === 'number' ? msg.total_cost_usd : undefined;
403	    acc.providerSessionId = typeof msg.session_id === 'string' ? msg.session_id : undefined;
404	
405	    const usage = msg.usage as Record<string, unknown> | undefined;
406	    if (usage) {
407	      acc.tokenUsage = {
408	        inputTokens: (typeof usage.input_tokens === 'number' ? usage.input_tokens : 0),
409	        outputTokens: (typeof usage.output_tokens === 'number' ? usage.output_tokens : 0),
410	        cacheReadTokens: typeof usage.cache_read_input_tokens === 'number'
411	          ? usage.cache_read_input_tokens : undefined,
412	        cacheWriteTokens: typeof usage.cache_creation_input_tokens === 'number'
413	          ? usage.cache_creation_input_tokens : undefined,
414	      };
415	    }
416	  }
417	
418	  return chunks;
419	}
420	
421	/**
422	 * Process NDJSON buffer, calling handler for each complete line.
423	 * Returns the remaining incomplete buffer.
424	 *
425	 * @internal Exported for testing only.
426	 */
427	export function processNdjsonBuffer(
428	  buffer: string,
429	  handler: (msg: Record<string, unknown>) => void,
430	): string {
431	  let newlineIdx: number;
432	  while ((newlineIdx = buffer.indexOf('\n')) !== -1) {
433	    const line = buffer.slice(0, newlineIdx).trim();
434	    buffer = buffer.slice(newlineIdx + 1);
435	
436	    if (!line) continue;
437	
438	    try {
439	      const msg = JSON.parse(line) as Record<string, unknown>;
440	      handler(msg);
441	    } catch {
442	      // Non-JSON line ‚Äî ignore
443	    }
444	  }
445	  return buffer;
446	}
447	
448	/**
449	 * Spawn Claude in autonomous mode with --output-format stream-json.
450	 *
451	 * Captures stdout (NDJSON lines), parses each line to extract:
452	 * - assistant messages ‚Üí transcript
453	 * - result message ‚Üí cost, token usage, session ID
454	 *
455	 * Forwards assistant text content to stderr so it's visible during execution.
456	 */
457	function spawnClaudeStreamJson(args: string[], cwd: string, env?: Record<string, string>, stdinData?: string): { result: Promise<StreamJsonResult>; pid: number } {
458	  const proc = spawn('claude', args, {
459	    cwd,
460	    stdio: ['pipe', 'pipe', 'inherit'],
461	    env: { ...process.env, ...env },
462	  });
463	
464	  // Pipe prompt via stdin (--print - reads from stdin)
465	  if (stdinData !== undefined) {
466	    proc.stdin!.write(stdinData);
467	    proc.stdin!.end();
468	  }
469	
470	  const acc: {
471	    transcript: Record<string, unknown>[];
472	    costUsd?: number;
473	    tokenUsage?: StreamJsonResult['tokenUsage'];
474	    providerSessionId?: string;
475	  } = { transcript: [] };
476	
477	  let buffer = '';
478	
479	  proc.stdout!.on('data', (chunk: Buffer) => {
480	    buffer += chunk.toString();
481	    buffer = processNdjsonBuffer(buffer, (msg) => {
482	      parseStreamJsonMessage(msg, acc);
483	    });
484	  });
485	
486	  const result = new Promise<StreamJsonResult>((resolve, reject) => {
487	    proc.on('error', (err) => {
488	      reject(new Error(`Failed to spawn claude: ${err.message}`));
489	    });
490	
491	    proc.on('close', (code) => {
492	      if (acc.transcript.length > 0) {
493	        process.stderr.write('\n');
494	      }
495	
496	      resolve({
497	        exitCode: code ?? 1,
498	        transcript: acc.transcript,
499	        costUsd: acc.costUsd,
500	        tokenUsage: acc.tokenUsage,
501	        providerSessionId: acc.providerSessionId,
502	      });
503	    });
504	  });
505	
506	  return { result, pid: proc.pid! };
507	}
508	
509	/**
510	 * Spawn Claude with streaming ‚Äî yields SessionChunks as they arrive
511	 * while also accumulating the full result.
512	 *
513	 * Returns an async iterable of chunks for real-time consumption and
514	 * a promise for the final StreamJsonResult.
515	 */
516	function spawnClaudeStreamingJson(args: string[], cwd: string, env?: Record<string, string>, stdinData?: string): {
517	  chunks: AsyncIterable<SessionChunk>;
518	  result: Promise<StreamJsonResult>;
519	  pid: number;
520	} {
521	  const chunkQueue: SessionChunk[] = [];
522	  let chunkResolve: (() => void) | null = null;
523	  let done = false;
524	
525	  const acc: {
526	    transcript: Record<string, unknown>[];
527	    costUsd?: number;
528	    tokenUsage?: StreamJsonResult['tokenUsage'];
529	    providerSessionId?: string;
530	  } = { transcript: [] };
531	
532	  const proc = spawn('claude', args, {
533	    cwd,
534	    stdio: ['pipe', 'pipe', 'inherit'],
535	    env: { ...process.env, ...env },
536	  });
537	
538	  // Pipe prompt via stdin (--print - reads from stdin)
539	  if (stdinData !== undefined) {
540	    proc.stdin!.write(stdinData);
541	    proc.stdin!.end();
542	  }
543	
544	  let buffer = '';
545	
546	  proc.stdout!.on('data', (chunk: Buffer) => {
547	    buffer += chunk.toString();
548	    buffer = processNdjsonBuffer(buffer, (msg) => {
549	      const newChunks = parseStreamJsonMessage(msg, acc);
550	      if (newChunks.length > 0) {
551	        chunkQueue.push(...newChunks);
552	        if (chunkResolve) {
553	          chunkResolve();
554	          chunkResolve = null;
555	        }
