20	  SessionProviderConfig,
21	  SessionProviderResult,
22	  SessionChunk,
23	  SessionDoc,
24	} from '@shardworks/animator-apparatus';
25	import type { StacksApi, ReadOnlyBook, Book } from '@shardworks/stacks-apparatus';
26	import type { ResolvedTool } from '@shardworks/tools-apparatus';
27	
28	import type { BabysitterConfig, SerializedTool } from './babysitter.ts';
29	
30	// ‚îÄ‚îÄ Constants ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
31	
32	/** Default poll interval for session status (ms). */
33	const POLL_INTERVAL_MS = 5_000;
34	/** Default poll timeout ‚Äî generous to allow long-running sessions (24h). */
35	const POLL_TIMEOUT_MS = 24 * 60 * 60 * 1_000;
36	/** Default tool server port (matches Instrumentarium default). */
37	const DEFAULT_TOOL_SERVER_PORT = 7471;
38	
39	// ‚îÄ‚îÄ Tool serialization ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
40	
41	/**
42	 * Serialize a ResolvedTool's Zod params to a SerializedTool with JSON Schema.
43	 *
44	 * Uses Zod 4's built-in `z.toJSONSchema()` to convert the params schema.
45	 * The resulting JSON Schema is what the babysitter's MCP proxy server
46	 * advertises to claude via tools/list.
47	 */
48	export function serializeTool(rt: ResolvedTool): SerializedTool {
49	  const def = rt.definition;
50	  const jsonSchema = z.toJSONSchema(def.params) as Record<string, unknown>;
51	
52	  // z.toJSONSchema returns a full JSON Schema object with type, properties, etc.
53	  // We extract the inner properties/required for the MCP tool registration,
54	  // since the babysitter wraps it in { type: 'object', ...params }.
55	  const { type: _type, $schema: _schema, ...params } = jsonSchema;
56	
57	  return {
58	    name: def.name,
59	    description: def.description,
60	    params,
61	  };
62	}
63	
64	/**
65	 * Serialize an array of ResolvedTools to SerializedTools.
66	 */
67	export function serializeTools(tools: ResolvedTool[]): SerializedTool[] {
68	  return tools.map(serializeTool);
69	}
70	
71	// ‚îÄ‚îÄ Guild config resolution ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
72	
73	/** Resolve the guild's Tool HTTP API URL. */
74	export function resolveGuildToolUrl(): string {
75	  const g = guild();
76	  // Match the Instrumentarium's port resolution logic:
77	  // guild.json["tools"]["serverPort"] ‚Üí default 7471
78	  const toolsConfig = g.config<{ serverPort?: number }>('tools');
79	  const port = toolsConfig?.serverPort ?? DEFAULT_TOOL_SERVER_PORT;
80	  return `http://127.0.0.1:${port}`;
81	}
82	
83	/** Resolve the path to the guild's SQLite database. */
84	export function resolveDbPath(): string {
85	  const g = guild();
86	  return path.join(g.home, '.nexus', 'nexus.db');
87	}
88	
89	/**
90	 * Resolve the babysitter script path, picking the .ts source or .js compiled
91	 * output to match how this module itself was loaded.
92	 *
93	 * - In compiled output (`dist/detached.js`) ‚Üí returns `dist/babysitter.js`.
94	 * - In source mode (`src/detached.ts` via --experimental-transform-types) ‚Üí
95	 *   returns `src/babysitter.ts`.
96	 *
97	 * The detection is by extension of the current module's URL. Without this,
98	 * source-mode runs (e.g. `nsg start --foreground` in dev) try to spawn a
99	 * non-existent `babysitter.js` and the babysitter dies with MODULE_NOT_FOUND
100	 * before it can call session-running.
101	 */
102	export function resolveBabysitterPath(): string {
103	  const dir = import.meta.dirname ?? path.dirname(new URL(import.meta.url).pathname);
104	  const isSource = import.meta.url.endsWith('.ts');
105	  return path.join(dir, isSource ? 'babysitter.ts' : 'babysitter.js');
106	}
107	
108	// ‚îÄ‚îÄ BabysitterConfig builder ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
109	
110	export interface DetachedLaunchOptions {
111	  /** Override babysitter script path (for testing). */
112	  babysitterPath?: string;
113	  /** Override guild tool URL (for testing). */
114	  guildToolUrl?: string;
115	  /** Override database path (for testing). */
116	  dbPath?: string;
117	  /** Override poll interval in ms (for testing). */
118	  pollIntervalMs?: number;
119	  /** Override poll timeout in ms (for testing). */
120	  pollTimeoutMs?: number;
121	  /** Override sessions book (for testing). */
122	  sessionsBook?: ReadOnlyBook<SessionDoc>;
123	  /** Override spawn function (for testing). */
124	  spawnFn?: typeof spawn;
125	  /** Session metadata from the AnimateRequest. */
126	  metadata?: Record<string, unknown>;
127	}
128	
129	/**
130	 * Build a BabysitterConfig from the provider's SessionProviderConfig.
131	 *
132	 * Serializes tools from Zod schemas to JSON Schema, resolves guild
133	 * infrastructure paths, and constructs the base CLI args for claude.
134	 */
135	export function buildBabysitterConfig(
136	  config: SessionProviderConfig,
137	  opts?: DetachedLaunchOptions,
138	): BabysitterConfig {
139	  // Build claude CLI args (same as the attached prepareSession() but without
140	  // --print, --output-format, --verbose, --mcp-config ‚Äî the babysitter adds those).
141	  const claudeArgs: string[] = [
142	    '--setting-sources', 'user',
143	    '--dangerously-skip-permissions',
144	    '--model', config.model,
145	  ];
146	
147	  // System prompt: write to a temp file and include --system-prompt-file in claudeArgs.
148	  // The file persists for the session duration ‚Äî acceptable for detached sessions.
149	  // The babysitter's tmpDir cleanup doesn't touch this, but OS tmp cleanup handles it.
150	  if (config.systemPrompt) {
151	    const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), 'nsg-detached-'));
152	    const systemPromptPath = path.join(tmpDir, 'system-prompt.md');
153	    fs.writeFileSync(systemPromptPath, config.systemPrompt);
154	    claudeArgs.push('--system-prompt-file', systemPromptPath);
155	  }
156	
157	  // Resume support
158	  if (config.conversationId) {
159	    claudeArgs.push('--resume', config.conversationId);
160	  }
161	
162	  return {
163	    sessionId: config.sessionId,
164	    guildToolUrl: opts?.guildToolUrl ?? resolveGuildToolUrl(),
165	    dbPath: opts?.dbPath ?? resolveDbPath(),
166	    claudeArgs,
167	    cwd: config.cwd,
168	    env: config.environment ?? {},
169	    prompt: config.initialPrompt ?? '',
170	    tools: serializeTools(config.tools ?? []),
171	    startedAt: new Date().toISOString(),
172	    provider: 'claude-code',
173	    metadata: opts?.metadata,
174	  };
175	}
176	
177	// ‚îÄ‚îÄ Polling helpers ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
178	
179	/**
180	 * Poll the sessions book until the session reaches a terminal status.
181	 *
182	 * Returns the SessionDoc when status is no longer 'running'.
183	 * Throws on timeout.
184	 */
185	export async function pollForTerminalStatus(
186	  sessionsBook: ReadOnlyBook<SessionDoc>,
187	  sessionId: string,
188	  pollIntervalMs: number = POLL_INTERVAL_MS,
189	  pollTimeoutMs: number = POLL_TIMEOUT_MS,
190	): Promise<SessionDoc> {
191	  const deadline = Date.now() + pollTimeoutMs;
192	
193	  while (Date.now() < deadline) {
194	    const doc = await sessionsBook.get(sessionId);
195	
196	    if (doc && doc.status !== 'running' && doc.status !== 'pending') {
197	      return doc;
198	    }
199	
200	    const remaining = deadline - Date.now();
201	    if (remaining <= 0) break;
202	
203	    await new Promise((resolve) => setTimeout(resolve, Math.min(pollIntervalMs, remaining)));
204	  }
205	
206	  throw new Error(
207	    `Session ${sessionId} did not reach terminal status within ${pollTimeoutMs}ms`,
208	  );
209	}
210	
211	/**
212	 * Poll the sessions book until cancelMetadata.pid is available.
213	 *
214	 * The babysitter reports the claude PID via the session-running tool,
215	 * which writes cancelMetadata to the SessionDoc. We poll for it.
216	 */
217	export async function pollForProcessInfo(
218	  sessionsBook: ReadOnlyBook<SessionDoc>,
219	  sessionId: string,
220	  pollIntervalMs: number = POLL_INTERVAL_MS,
221	  pollTimeoutMs: number = 60_000,
222	): Promise<Record<string, unknown>> {
223	  const deadline = Date.now() + pollTimeoutMs;
224	
225	  while (Date.now() < deadline) {
226	    const doc = await sessionsBook.get(sessionId);
227	
228	    if (doc?.cancelMetadata) {
229	      return doc.cancelMetadata;
230	    }
231	
232	    // If the session already terminated, return empty (no process to cancel)
233	    if (doc && doc.status !== 'running' && doc.status !== 'pending') {
234	      return {};
235	    }
236	
237	    const remaining = deadline - Date.now();
238	    if (remaining <= 0) break;
239	
240	    await new Promise((resolve) => setTimeout(resolve, Math.min(pollIntervalMs, remaining)));
241	  }
242	
243	  // Timeout ‚Äî return empty rather than throwing. The babysitter PID is a
244	  // fallback anyway, and the session might still be starting up.
245	  return {};
246	}
247	
248	// ‚îÄ‚îÄ Detached launch ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
249	
250	/**
251	 * Build a SessionProviderResult from a terminal SessionDoc.
252	 */
253	function docToProviderResult(doc: SessionDoc): SessionProviderResult {
254	  const status: SessionProviderResult['status'] =
255	    doc.status === 'running' || doc.status === 'pending'
256	      ? 'failed'
257	      : doc.status;
258	  return {
259	    status,
260	    exitCode: doc.exitCode ?? 1,
261	    error: doc.error,
262	    providerSessionId: doc.providerSessionId,
263	    tokenUsage: doc.tokenUsage,
264	    costUsd: doc.costUsd,
265	    output: doc.output,
266	    // Note: transcript is not included here ‚Äî it's in the transcripts book.
267	    // The babysitter writes it directly to SQLite.
268	  };
269	}
270	
271	/**
272	 * Launch a detached babysitter process.
273	 *
274	 * Returns the same { chunks, result, processInfo } shape as the attached
275	 * provider, but:
276	 * - chunks: completes immediately (empty) ‚Äî transcripts stream to SQLite
277	 * - result: polls sessions book for terminal status
278	 * - processInfo: polls SessionDoc for cancelMetadata (contains claude PID)
279	 */
280	export function launchDetached(
281	  config: SessionProviderConfig,
282	  opts?: DetachedLaunchOptions,
283	): {
284	  chunks: AsyncIterable<SessionChunk>;
285	  result: Promise<SessionProviderResult>;
286	  processInfo?: Promise<Record<string, unknown>>;
287	} {
288	  const babysitterPath = opts?.babysitterPath ?? resolveBabysitterPath();
289	  const pollIntervalMs = opts?.pollIntervalMs ?? POLL_INTERVAL_MS;
290	  const pollTimeoutMs = opts?.pollTimeoutMs ?? POLL_TIMEOUT_MS;
291	  const spawnFn = opts?.spawnFn ?? spawn;
292	
293	  // Resolve sessions book lazily to avoid import-time guild() calls
294	  const getSessionsBook = (): ReadOnlyBook<SessionDoc> => {
295	    if (opts?.sessionsBook) return opts.sessionsBook;
296	    const stacks = guild().apparatus<StacksApi>('stacks');
297	    return stacks.readBook<SessionDoc>('animator', 'sessions');
298	  };
299	  const getWritableSessionsBook = (): Book<SessionDoc> => {
300	    const stacks = guild().apparatus<StacksApi>('stacks');
301	    return stacks.book<SessionDoc>('animator', 'sessions');
302	  };
303	
304	  // Build babysitter config
305	  const babysitterConfig = buildBabysitterConfig(config, opts);
306	
307	  // Compute the full authorized tool set for this session: every tool the
308	  // session was composed with, plus the two infrastructure tools it needs
309	  // to report its own lifecycle back to the guild.
310	  const authorizedTools = [
311	    ...(config.tools?.map((rt) => rt.definition.name) ?? []),
312	    'session-running',
313	    'session-record',
314	  ];
315	
316	  // Pre-write a `pending` SessionDoc BEFORE spawning the babysitter. This
317	  // is the source of truth for the tool server's authorize callback: by
318	  // the time the babysitter's first HTTP call lands, the sessions book
319	  // already records the session and the tools it's allowed to call.
320	  //
321	  // The babysitter's `session-running` call will merge this doc into a
322	  // `running` one, preserving authorizedTools.
323	  //
324	  // Fire-and-forget ‚Äî spawn must not block on this. In the worst case
325	  // the babysitter will retry its first HTTP call for up to 60s, which
326	  // is plenty of time for the SQLite write to land.
327	  (async () => {
328	    try {
329	      const sessions = getWritableSessionsBook();
330	      await sessions.put({
331	        id: config.sessionId,
332	        status: 'pending',
333	        startedAt: new Date().toISOString(),
334	        provider: 'claude-code',
335	        authorizedTools,
336	        ...(opts?.metadata ? { metadata: opts.metadata } : {}),
337	      });
338	    } catch (err) {
339	      console.warn(
340	        `[claude-code] Failed to pre-write pending session ${config.sessionId}: ${err instanceof Error ? err.message : err}`,
341	      );
342	    }
343	  })();
344	
345	  // Spawn the babysitter as a detached process.
346	  // stdio: ['pipe', 'ignore', 'inherit'] ‚Äî config via stdin, no stdout, stderr to parent
347	  //
348	  // In source mode (.ts babysitter), forward the parent's execArgv so that
349	  // --experimental-transform-types (and friends) reach the child. Without
350	  // this, node would try to load a .ts file as plain CommonJS and crash.
351	  const isSource = babysitterPath.endsWith('.ts');
352	  const nodeArgs = isSource
353	    ? [...process.execArgv, babysitterPath]
354	    : [babysitterPath];
355	  const proc = spawnFn(process.execPath, nodeArgs, {
356	    cwd: config.cwd,
357	    stdio: ['pipe', 'ignore', 'inherit'],
358	    detached: true,
359	    env: { ...process.env, ...config.environment },
360	  });
361	
362	  // Write config to the babysitter's stdin, then close it.
363	  proc.stdin!.write(JSON.stringify(babysitterConfig));
364	  proc.stdin!.end();
365	
366	  // Detach ‚Äî guild doesn't wait for the babysitter.
367	  proc.unref();
368	
369	  // Empty chunks ‚Äî real-time output is via the transcripts book, not in-memory.
370	  const chunks: AsyncIterable<SessionChunk> = {
371	    [Symbol.asyncIterator]() {
372	      return {
373	        async next() {
374	          return { value: undefined as unknown as SessionChunk, done: true };
375	        },
376	      };
377	    },
378	  };
379	
380	  // Result: poll sessions book for terminal status.
381	  const result = (async (): Promise<SessionProviderResult> => {
382	    try {
383	      const sessionsBook = getSessionsBook();
384	      const doc = await pollForTerminalStatus(
385	        sessionsBook,
386	        config.sessionId,
387	        pollIntervalMs,
388	        pollTimeoutMs,
389	      );
390	      return docToProviderResult(doc);
391	    } catch (err) {
392	      return {
393	        status: 'failed',
394	        exitCode: 1,
395	        error: `Detached session polling failed: ${err instanceof Error ? err.message : String(err)}`,
396	      };
397	    }
398	  })();
399	
400	  // processInfo: poll for cancelMetadata (contains claude PID from babysitter).
401	  // Falls back to the babysitter's own PID.
402	  const processInfo = (async (): Promise<Record<string, unknown>> => {
403	    try {
404	      const sessionsBook = getSessionsBook();
405	      const info = await pollForProcessInfo(
406	        sessionsBook,
407	        config.sessionId,
408	        pollIntervalMs,
409	      );
410	      if (Object.keys(info).length > 0) return info;
411	    } catch {
412	      // Fall through to babysitter PID
413	    }
414	    // Fallback: return babysitter PID. Signals to the babysitter process group
415	    // leader (detached: true) can still reach claude via process group.
416	    return { pid: proc.pid };
417	  })();
418	
419	  return { chunks, result, processInfo };
420	}
