213	// ‚îÄ‚îÄ MCP proxy server ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
214	
215	/**
216	 * Create an MCP/SSE HTTP server that proxies tool calls to the guild.
217	 *
218	 * For each tool in the config, registers an MCP tool whose handler
219	 * forwards the call to the guild's Tool HTTP API via HTTP POST.
220	 *
221	 * Uses the low-level MCP Server class to register tools with raw
222	 * JSON Schema (the serialized params from the config).
223	 */
224	export async function createProxyMcpHttpServer(
225	  tools: SerializedTool[],
226	  guildToolUrl: string,
227	  sessionId: string,
228	): Promise<McpProxyHandle> {
229	  const server = new Server(
230	    { name: 'nexus-guild-proxy', version: '0.0.0' },
231	    { capabilities: { tools: {} } },
232	  );
233	
234	  // Register tools/list handler ‚Äî advertises all tools with their JSON Schema.
235	  server.setRequestHandler(ListToolsRequestSchema, async () => ({
236	    tools: tools.map((t) => ({
237	      name: t.name,
238	      description: t.description,
239	      inputSchema: {
240	        type: 'object' as const,
241	        ...t.params,
242	      },
243	    })),
244	  }));
245	
246	  // Register tools/call handler ‚Äî proxies each call to the guild HTTP API.
247	  server.setRequestHandler(CallToolRequestSchema, async (request) => {
248	    const toolName = request.params.name;
249	    const params = request.params.arguments ?? {};
250	
251	    const route = toolNameToRoute(toolName);
252	    const url = `${guildToolUrl}${route}`;
253	
254	    try {
255	      const result = await callGuildHttpApi(url, sessionId, params);
256	      const text = typeof result === 'string' ? result : JSON.stringify(result, null, 2);
257	      return {
258	        content: [{ type: 'text' as const, text }],
259	      };
260	    } catch (err) {
261	      const message = err instanceof Error ? err.message : String(err);
262	      return {
263	        content: [{ type: 'text' as const, text: `Error: ${message}` }],
264	        isError: true,
265	      };
266	    }
267	  });
268	
269	  // Wrap in HTTP server with SSE transport (same pattern as mcp-server.ts).
270	  // Promise-gate: POST /message waits for the SSE transport to be fully connected,
271	  // eliminating the race where a POST arrives before GET /sse completes.
272	  let resolveTransport!: (t: SSEServerTransport) => void;
273	  let rejectTransport!: (err: Error) => void;
274	  const transportReady = new Promise<SSEServerTransport>((resolve, reject) => {
275	    resolveTransport = resolve;
276	    rejectTransport = reject;
277	  });
278	
279	  // Direct reference for close() ‚Äî null until connected.
280	  let transport: SSEServerTransport | null = null;
281	
282	  const httpServer = http.createServer(async (req, res) => {
283	    try {
284	      if (req.method === 'GET' && req.url === '/sse') {
285	        const t = new SSEServerTransport('/message', res);
286	        try {
287	          await server.connect(t);
288	          transport = t;
289	          resolveTransport(t);
290	        } catch (err) {
291	          rejectTransport(err instanceof Error ? err : new Error(String(err)));
292	          throw err;
293	        }
294	      } else if (req.method === 'POST' && req.url?.startsWith('/message')) {
295	        if (!transport) {
296	          process.stderr.write(`[babysitter] POST /message arrived before SSE transport ready ‚Äî waiting\n`);
297	        }
298	        let t: SSEServerTransport;
299	        try {
300	          t = await transportReady;
301	        } catch {
302	          res.writeHead(503).end('SSE transport failed to initialize');
303	          return;
304	        }
305	        await t.handlePostMessage(req, res);
306	      } else {
307	        res.writeHead(404).end('Not found');
308	      }
309	    } catch {
310	      if (!res.headersSent) {
311	        res.writeHead(500).end('Internal Server Error');
312	      }
313	    }
314	  });
315	
316	  await new Promise<void>((resolve) => {
317	    httpServer.listen(0, '127.0.0.1', resolve);
318	  });
319	
320	  const addr = httpServer.address();
321	  if (!addr || typeof addr === 'string') {
322	    throw new Error('Failed to get MCP proxy server address');
323	  }
324	
325	  const url = `http://127.0.0.1:${addr.port}/sse`;
326	  process.stderr.write(`[babysitter] MCP proxy server listening on port ${addr.port}\n`);
327	
328	  return {
329	    url,
330	    async close() {
331	      if (transport) {
332	        await transport.close();
333	      }
334	      await new Promise<void>((resolve, reject) => {
335	        httpServer.close((err) => (err ? reject(err) : resolve()));
336	      });
337	    },
338	  };
339	}
340	
341	// ‚îÄ‚îÄ SQLite transcript writer ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
342	
343	/** Minimal interface for the SQLite database used by the babysitter. */
344	export interface TranscriptDb {
345	  /** Write a transcript entry (id, content JSON). */
346	  writeTranscript(sessionId: string, content: string): void;
347	  /** Close the database connection. */
348	  close(): void;
349	}
350	
351	/**
352	 * Open the guild's SQLite database for transcript streaming.
353	 *
354	 * Creates the database file and table if they don't exist.
355	 * Enables WAL mode for concurrent read access by other processes
356	 * (Oculus, CLI queries, other agents).
357	 *
358	 * Uses dynamic import() to load better-sqlite3 at runtime. This avoids
359	 * requiring the native module at import time (beneficial for type-checking
360	 * and testing).
361	 */
362	export async function openTranscriptDb(dbPath: string): Promise<TranscriptDb> {
363	  const { default: Database } = await import('better-sqlite3');
364	  return initTranscriptDb(Database, dbPath);
365	}
366	
367	/**
368	 * Initialize a TranscriptDb from a Database constructor.
369	 *
370	 * Shared logic between openTranscriptDb() and test injection.
371	 * Exported for testing ‚Äî allows injecting a mock Database constructor.
372	 */
373	export function initTranscriptDb(
374	  DatabaseConstructor: new (path: string) => {
375	    pragma(stmt: string): unknown;
376	    prepare(sql: string): { run(...params: unknown[]): void };
377	    exec(sql: string): void;
378	    close(): void;
379	  },
380	  dbPath: string,
381	): TranscriptDb {
382	  const raw = new DatabaseConstructor(dbPath);
383	  raw.pragma('journal_mode = WAL');
384	  raw.exec(`
385	    CREATE TABLE IF NOT EXISTS books_animator_transcripts (
386	      id      TEXT PRIMARY KEY,
387	      content TEXT NOT NULL
388	    )
389	  `);
390	  const stmt = raw.prepare(
391	    'INSERT OR REPLACE INTO books_animator_transcripts (id, content) VALUES (?, ?)',
392	  );
393	
394	  return {
395	    writeTranscript(sessionId: string, content: string) {
396	      stmt.run(sessionId, content);
397	    },
398	    close() {
399	      raw.close();
400	    },
401	  };
402	}
403	
404	/**
405	 * Write the current transcript to SQLite.
406	 */
407	export function writeTranscript(
408	  db: TranscriptDb,
409	  sessionId: string,
410	  messages: Record<string, unknown>[],
411	): void {
412	  const content = JSON.stringify({ id: sessionId, messages });
413	  db.writeTranscript(sessionId, content);
414	}
415	
416	// ‚îÄ‚îÄ Session lifecycle reporting ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
417	
418	/**
419	 * Report "running" status to the guild via the session-running tool.
420	 *
421	 * If the guild is unreachable, writes the payload to the DLQ.
422	 */
423	export async function reportRunning(
424	  config: BabysitterConfig,
425	  claudePid: number,
426	  timeoutMs?: number,
427	): Promise<void> {
428	  const route = toolNameToRoute('session-running');
429	  const url = `${config.guildToolUrl}${route}`;
430	  const payload = {
431	    sessionId: config.sessionId,
432	    startedAt: config.startedAt,
433	    provider: config.provider,
434	    metadata: config.metadata,
435	    cancelMetadata: { pid: claudePid },
436	  };
437	
438	  try {
439	    await callGuildHttpApi(url, config.sessionId, payload, timeoutMs);
440	  } catch {
441	    writeToDlq(config.cwd, `${config.sessionId}-running.json`, payload);
442	  }
443	}
444	
445	/**
446	 * Report the final session result to the guild via the session-record tool.
447	 *
448	 * If the guild is unreachable, writes the payload to the DLQ.
449	 */
450	export async function reportResult(
451	  config: BabysitterConfig,
452	  result: StreamJsonResult,
453	  transcript: Record<string, unknown>[],
454	  timeoutMs?: number,
455	): Promise<void> {
456	  const route = toolNameToRoute('session-record');
457	  const url = `${config.guildToolUrl}${route}`;
458	  const status = result.exitCode === 0 ? 'completed' : 'failed';
459	  const output = extractFinalAssistantText(transcript);
460	
461	  const payload = {
462	    sessionId: config.sessionId,
463	    status,
464	    exitCode: result.exitCode,
465	    error: status === 'failed' ? `claude exited with code ${result.exitCode}` : undefined,
466	    costUsd: result.costUsd,
467	    tokenUsage: result.tokenUsage,
468	    output,
469	    providerSessionId: result.providerSessionId,
470	    transcript,
471	  };
472	
473	  try {
474	    await callGuildHttpApi(url, config.sessionId, payload, timeoutMs);
475	  } catch {
476	    writeToDlq(config.cwd, `${config.sessionId}.json`, payload);
477	  }
478	}
479	
480	// ‚îÄ‚îÄ Main babysitter function ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
481	
482	/**
483	 * Run the session babysitter.
484	 *
485	 * This is the main orchestration function. It:
486	 * 1. Opens SQLite for transcript streaming
487	 * 2. Starts the MCP proxy server
488	 * 3. Prepares session files (tmpDir, system prompt, mcp-config)
489	 * 4. Spawns claude
490	 * 5. Reports "running" status
491	 * 6. Streams transcript to SQLite
492	 * 7. Reports result on exit
493	 * 8. Cleans up
494	 */
495	export async function runBabysitter(
496	  config: BabysitterConfig,
497	  deps?: {
498	    /** Injected TranscriptDb for testing (avoids loading better-sqlite3). */
499	    db?: TranscriptDb;
500	    /** Override spawn for testing. */
501	    spawnFn?: typeof spawn;
502	    /** Override retry timeout for testing (default: 60_000ms). */
503	    retryTimeoutMs?: number;
504	  },
505	): Promise<void> {
506	  const spawnFn = deps?.spawnFn ?? spawn;
507	  const retryTimeoutMs = deps?.retryTimeoutMs;
508	  let db: TranscriptDb | null = null;
509	  let mcpHandle: McpProxyHandle | null = null;
510	  let tmpDir: string | null = null;
511	  let claudeProc: ChildProcess | null = null;
512	
513	  try {
514	    // 1. Open SQLite
515	    db = deps?.db ?? await openTranscriptDb(config.dbPath);
516	
517	    // 2. Start MCP proxy server
518	    mcpHandle = await createProxyMcpHttpServer(
519	      config.tools,
520	      config.guildToolUrl,
521	      config.sessionId,
522	    );
523	
524	    // 3. Prepare session files
525	    tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), 'nsg-babysitter-'));
526	
527	    const args = [...config.claudeArgs];
528	
529	    // Write system prompt if present in args (already handled by claudeArgs)
530	    // Write mcp-config pointing to the babysitter's MCP proxy server
531	    const mcpConfig = {
532	      mcpServers: {
533	        'nexus-guild': {
534	          type: 'sse',
535	          url: mcpHandle.url,
536	        },
537	      },
538	    };
539	    const mcpConfigPath = path.join(tmpDir, 'mcp-config.json');
540	    fs.writeFileSync(mcpConfigPath, JSON.stringify(mcpConfig));
541	    args.push('--mcp-config', mcpConfigPath, '--strict-mcp-config');
542	
543	    // Add autonomous mode flags
544	    args.push(
545	      '--print', '-',
546	      '--output-format', 'stream-json',
547	      '--verbose',
548	    );
549	
550	    // 4. Spawn claude
551	    claudeProc = spawnFn('claude', args, {
552	      cwd: config.cwd,
553	      stdio: ['pipe', 'pipe', 'inherit'],
554	      env: { ...process.env, ...config.env },
555	    });
556	
557	    // Pipe prompt to claude's stdin, then close
558	    if (config.prompt) {
559	      claudeProc.stdin!.write(config.prompt);
560	    }
561	    claudeProc.stdin!.end();
562	
563	    // 5. Report "running" status (don't await ‚Äî fire and forget with retry)
564	    const runningPromise = reportRunning(config, claudeProc.pid!, retryTimeoutMs).catch((err) => {
565	      process.stderr.write(`[babysitter] Failed to report running: ${err}\n`);
566	    });
567	
568	    // 6. Consume stdout, stream transcript
569	    const acc: {
570	      transcript: Record<string, unknown>[];
571	      costUsd?: number;
572	      tokenUsage?: StreamJsonResult['tokenUsage'];
573	      providerSessionId?: string;
574	    } = { transcript: [] };
575	
576	    let buffer = '';
577	
578	    claudeProc.stdout!.on('data', (chunk: Buffer) => {
579	      buffer += chunk.toString();
580	      const prevLength = acc.transcript.length;
581	      buffer = processNdjsonBuffer(buffer, (msg) => {
582	        parseStreamJsonMessage(msg, acc);
583	      });
584	
585	      // Write transcript to SQLite if new messages were added
586	      if (acc.transcript.length > prevLength && db) {
587	        writeTranscript(db, config.sessionId, acc.transcript);
588	      }
589	    });
590	
591	    // 7. Wait for claude to exit
592	    const exitCode = await new Promise<number>((resolve, reject) => {
593	      claudeProc!.on('error', (err) => {
594	        reject(new Error(`Failed to spawn claude: ${err.message}`));
595	      });
596	      claudeProc!.on('close', (code) => {
597	        resolve(code ?? 1);
598	      });
599	    });
600	
601	    // Ensure running report completed before recording result
602	    await runningPromise;
603	
604	    // Build result
605	    const result: StreamJsonResult = {
606	      exitCode,
607	      transcript: acc.transcript,
608	      costUsd: acc.costUsd,
609	      tokenUsage: acc.tokenUsage,
610	      providerSessionId: acc.providerSessionId,
611	    };
612	
613	    // 8. Report result
614	    await reportResult(config, result, acc.transcript, retryTimeoutMs);
615	  } catch (err) {
616	    // Top-level error: attempt to report failure
617	    const message = err instanceof Error ? err.message : String(err);
618	
619	    try {
620	      const route = toolNameToRoute('session-record');
621	      const url = `${config.guildToolUrl}${route}`;
622	      await callGuildHttpApi(url, config.sessionId, {
623	        sessionId: config.sessionId,
624	        status: 'failed',
625	        exitCode: 1,
626	        error: message,
627	      }, retryTimeoutMs);
628	    } catch {
629	      writeToDlq(config.cwd, `${config.sessionId}.json`, {
630	        sessionId: config.sessionId,
631	        status: 'failed',
632	        exitCode: 1,
633	        error: message,
634	      });
635	    }
636	
637	    throw err;
638	  } finally {
639	    // 9. Cleanup
640	    await mcpHandle?.close().catch(() => {});
641	    db?.close();
642	    if (tmpDir) {
643	      fs.rmSync(tmpDir, { recursive: true, force: true });
644	    }
645	  }
646	}
647	
648	// ‚îÄ‚îÄ Entry point ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
649	
650	/**
651	 * Script entry point ‚Äî reads config from stdin and runs the babysitter.
652	 *
653	 * Only executes when this file is run directly (not when imported).
654	 */
655	async function main(): Promise<void> {
656	  try {
657	    const config = await readConfigFromStdin();
658	    await runBabysitter(config);
659	    process.exit(0);
660	  } catch (err) {
661	    process.stderr.write(
662	      `[babysitter] Fatal error: ${err instanceof Error ? err.message : String(err)}\n`,
663	    );
664	    process.exit(1);
665	  }
666	}
667	
668	// Check if this module is the entry point
669	const isEntryPoint = process.argv[1] &&
670	  (process.argv[1] === fileURLToPath(import.meta.url) ||
671	   process.argv[1].endsWith('/babysitter.js'));
672	
673	if (isEntryPoint) {
674	  main();
675	}
676

