28	 */
29	export async function drainDlq(guildHome: string): Promise<number> {
30	  const dlqDir = path.join(guildHome, '.nexus', 'dlq');
31	
32	  // Ensure the directory exists.
33	  try {
34	    fs.mkdirSync(dlqDir, { recursive: true });
35	  } catch {
36	    // Best-effort ‚Äî if we can't create it, there's nothing to drain.
37	  }
38	
39	  let files: string[];
40	  try {
41	    files = fs.readdirSync(dlqDir).filter((f) => f.endsWith('.json'));
42	  } catch {
43	    return 0;
44	  }
45	
46	  if (files.length === 0) return 0;
47	
48	  let processed = 0;
49	  for (const file of files) {
50	    const filePath = path.join(dlqDir, file);
51	    try {
52	      const raw = fs.readFileSync(filePath, 'utf-8');
53	      const payload = JSON.parse(raw) as SessionRecordParams;
54	
55	      await handleSessionRecord(payload);
56	
57	      // Delete the file after successful processing.
58	      fs.unlinkSync(filePath);
59	      processed++;
60	    } catch (err) {
61	      console.warn(
62	        `[animator] Failed to process DLQ file ${file}: ${err instanceof Error ? err.message : err}`,
63	      );
64	    }
65	  }
66	
67	  if (processed > 0) {
68	    console.log(`[animator] DLQ drain: processed ${processed} of ${files.length} pending session results`);
69	  }
70	
71	  return processed;
72	}
73	
74	// ‚îÄ‚îÄ Orphan recovery ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
75	
76	/**
77	 * Find sessions stuck in 'running' and check if their process is still alive.
78	 *
79	 * For each running session with a PID in cancelMetadata:
80	 * - If the process is dead (ESRCH): mark as failed with an orphan error.
81	 * - If alive or no PID: skip (legitimately running or pre-detached).
82	 *
83	 * Runs after DLQ drain so DLQ'd results are processed first (a DLQ'd
84	 * result might resolve what would otherwise look like an orphan).
85	 */
86	export async function recoverOrphans(sessions: Book<SessionDoc>): Promise<number> {
87	  const runningSessions = await sessions.find({
88	    where: [['status', '=', 'running']],
89	  });
90	
91	  let recovered = 0;
92	  for (const doc of runningSessions) {
93	    const pid = doc.cancelMetadata?.pid;
94	    if (typeof pid !== 'number') {
95	      // No PID ‚Äî pre-detached session or session without cancel metadata. Skip.
96	      continue;
97	    }
98	
99	    if (isProcessAlive(pid)) {
100	      // Process is still running ‚Äî legitimate session. Skip.
101	      continue;
102	    }
103	
104	    // Process is dead ‚Äî mark as failed.
105	    const endedAt = new Date().toISOString();
106	    const durationMs = new Date(endedAt).getTime() - new Date(doc.startedAt).getTime();
107	
108	    const updated: SessionDoc = {
109	      ...doc,
110	      status: 'failed',
111	      endedAt,
112	      durationMs,
113	      exitCode: 1,
114	      error: 'Session process died unexpectedly (orphaned)',
115	    };
116	
117	    try {
118	      await sessions.put(updated);
119	      recovered++;
120	    } catch (err) {
121	      console.warn(
122	        `[animator] Failed to recover orphaned session ${doc.id}: ${err instanceof Error ? err.message : err}`,
123	      );
124	    }
125	  }
126	
127	  if (recovered > 0) {
128	    console.log(`[animator] Orphan recovery: marked ${recovered} dead sessions as failed`);
129	  }
130	
131	  return recovered;
132	}
133	
134	/**
135	 * Check if a process with the given PID is alive.
136	 *
137	 * Uses process.kill(pid, 0) which sends signal 0 (no-op) to check
138	 * existence. Returns true if alive, false if dead (ESRCH).
139	 */
140	export function isProcessAlive(pid: number): boolean {
141	  try {
142	    process.kill(pid, 0);
143	    return true;
144	  } catch (err: unknown) {
145	    const code = (err as NodeJS.ErrnoException).code;
146	    if (code === 'ESRCH') {
147	      // No such process ‚Äî it's dead.
148	      return false;
149	    }
150	    // EPERM means the process exists but we can't signal it.
151	    // Treat as alive ‚Äî it's not our orphan.
152	    return true;
153	  }
154	}
